package com.oneil.wellness.walkplanner.history;

import java.time.*;import java.util.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;

@Service
public class RecommendationHistoryService {
    private final HistoryRepository repository;
    public RecommendationHistoryService(HistoryRepository repository){this.repository=repository;}
    @Transactional public RecommendationSnapshot record(RecommendationSnapshot value){validate(value);var latest=repository.findTopByOrderByCapturedAtDesc().map(RecommendationHistory::snapshot);if(latest.isPresent()&&!meaningful(latest.get(),value))return latest.get();repository.save(new RecommendationHistory(value));return value;}
    public HistoryResponse history(){Instant weekStart=LocalDate.now().minusDays(6).atStartOfDay(ZoneId.systemDefault()).toInstant();List<RecommendationSnapshot> values=repository.findByCapturedAtAfterOrderByCapturedAtAsc(weekStart).stream().map(RecommendationHistory::snapshot).toList();LocalDate today=LocalDate.now();List<RecommendationSnapshot> todayValues=values.stream().filter(v->v.timestamp().atZone(ZoneId.systemDefault()).toLocalDate().equals(today)).toList();return new HistoryResponse(values,summary(todayValues),summary(values),comparison(values));}
    boolean meaningful(RecommendationSnapshot a,RecommendationSnapshot b){return Math.abs(a.score()-b.score())>=3||!a.recommendedStart().equals(b.recommendedStart())||a.calendarAvailable()!=b.calendarAvailable()||!a.providerSources().equals(b.providerSources())||!a.reasonSummary().equals(b.reasonSummary());}
    private void validate(RecommendationSnapshot v){if(v==null||v.recommendedStart()==null||v.recommendedEnd()==null||!v.recommendedStart().isBefore(v.recommendedEnd())||v.score()<0||v.score()>100)throw new IllegalArgumentException("A valid recommendation snapshot is required.");}
    private HistorySummary summary(List<RecommendationSnapshot> values){if(values.isEmpty())return new HistorySummary(0,null,null,0,0,0,0,null,null,null,null,null,List.of());var best=values.stream().max(Comparator.comparingInt(RecommendationSnapshot::score)).orElseThrow();Map<LocalDate,List<RecommendationSnapshot>> days=new HashMap<>();values.forEach(v->days.computeIfAbsent(v.timestamp().atZone(ZoneId.systemDefault()).toLocalDate(),k->new ArrayList<>()).add(v));LocalDate bestDay=days.entrySet().stream().max(Comparator.comparingDouble(e->e.getValue().stream().mapToInt(RecommendationSnapshot::score).average().orElse(0))).map(Map.Entry::getKey).orElse(null);LocalDate blocked=days.entrySet().stream().max(Comparator.comparingLong(e->e.getValue().stream().filter(v->!v.calendarAvailable()).count())).map(Map.Entry::getKey).orElse(null);return new HistorySummary(round(values.stream().mapToInt(RecommendationSnapshot::score).average().orElse(0)),best.score(),best.recommendedStart().toString(),(int)values.stream().filter(v->v.calendarAvailable()&&v.score()>=60).count(),(int)values.stream().filter(v->!v.calendarAvailable()).count(),(int)values.stream().filter(v->v.score()<60).count(),(int)values.stream().filter(v->!v.calendarAvailable()||v.score()<60).count(),bestDay,blocked,average(values,RecommendationSnapshot::temperature),average(values,RecommendationSnapshot::aqi),average(values,RecommendationSnapshot::uv),values.stream().flatMap(v->v.providerSources().stream()).distinct().sorted().toList());}
    private RecommendationComparison comparison(List<RecommendationSnapshot> values){if(values.size()<2)return null;var previous=values.get(values.size()-2);var current=values.getLast();List<String> reasons=new ArrayList<>();difference(reasons,"Higher wind",previous.wind(),current.wind(),2,true);difference(reasons,"Higher UV",previous.uv(),current.uv(),1,true);difference(reasons,"Lower humidity",previous.humidity(),current.humidity(),8,false);difference(reasons,"Temperature changed",previous.temperature(),current.temperature(),5,true);if(previous.calendarAvailable()!=current.calendarAvailable())reasons.add(current.calendarAvailable()?"Calendar became available":"Calendar conflict added");return new RecommendationComparison(previous,current,current.score()-previous.score(),reasons);}
    private void difference(List<String> reasons,String label,Double before,Double after,double threshold,boolean increase){if(before!=null&&after!=null&&Math.abs(after-before)>=threshold&&(!increase||after>before))reasons.add(label);}
    private Double average(List<RecommendationSnapshot> values,java.util.function.Function<RecommendationSnapshot,Double> field){var numbers=values.stream().map(field).filter(Objects::nonNull).mapToDouble(Double::doubleValue).toArray();return numbers.length==0?null:round(Arrays.stream(numbers).average().orElse(0));}
    private double round(double value){return Math.round(value*10.0)/10.0;}
}
